		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			assignCopy := dispatch.Assigns[ii]
			if assignCopy.AddShip(shipID, ori, des) {
				oldCost := assignCopy.Cost
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				costIncrease := 1e308
				if newCost >= 0 {
					costIncrease = newCost - oldCost
					if costIncrease < bestCostIncrease {
						bestCostIncrease = costIncrease
						bestIdx = ii
					}
				}
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			inserted = true
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				emptyIdx := -1
				for ii := 0; ii < MAXASSIGNS; ii++ {
					found := false
