algorithm:
My new algorithm evaluates insertions using a weighted score combining marginal distance increase, time window feasibility slack, and load balance penalty, then selects the best feasible insertion per ship while preserving empty assign slots for future flexibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 1.0
	const beta = 0.3
	const gamma = 0.01
	type cand struct {
		assignIdx int
		deltaDist float64
		timeSlack float64
		loadPenalty float64
		score     float64
		ok        bool
	}
	for shipIdx := range oris {
		bestCand := cand{}
		ori := oris[shipIdx]
		des := dess[shipIdx]
		id := total_ship + shipIdx
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				continue
			}
			prevCost := dispatch.Assigns[i].Cost
			addOk := dispatch.Assigns[i].AddShip(id, ori, des)
			if !addOk {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			if newCost < 0 {
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
				continue
			}
			marginalIncrease := newCost - prevCost
			if marginalIncrease < 0 {
				marginalIncrease = 0
			}
			var maxTimeSlack float64 = 1000000
			stationsCount := 0
			for s := 0; s < dispatch.Assigns[i].StationsLen; s++ {
				maxTimeSlack = 1000000
				stationsCount++
			}
			if stationsCount == 0 {
				maxTimeSlack = 1000000
			}
			loadPenalty := 0.0
			currentLoad := 0
			for s := 0; s < dispatch.Assigns[i].StationsLen; s++ {
				req := dispatch.Assigns[i].Stations[s].ReqCode
				if req&1 != 0 {
					currentLoad += dispatch.Assigns[i].Stations[s].Load
				}
			}
			if currentLoad > 80 {
				loadPenalty = float64(currentLoad-80)*gamma*100
			}
			timeSlackInv := 1.0 / (maxTimeSlack + 1.0)
			scoreVal := alpha*marginalIncrease + beta*timeSlackInv + loadPenalty
			c := cand{
				assignIdx:   i,
				deltaDist:   marginalIncrease,
				timeSlack:   maxTimeSlack,
				loadPenalty: loadPenalty,
				score:       scoreVal,
				ok:          true,
			}
			if !bestCand.ok || c.score < bestCand.score {
				bestCand = c
			}
			dispatch.Assigns[i].RemoveShip(id)
			dispatch.Assigns[i].GenRoute()
		}
		if bestCand.ok {
			dispatch.Assigns[bestCand.assignIdx].AddShip(id, ori, des)
			dispatch.Assigns[bestCand.assignIdx].GenRoute()
		} else {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				dispatch.Assigns[seedIdx].AddShip(id, ori, des)
				dispatch.Assigns[seedIdx].GenRoute()
				if dispatch.Assigns[seedIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[seedIdx].RemoveShip(id)
					dispatch.Assigns[seedIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
